class SecureWebViewController: UIViewController {
    
    private var webView: WKWebView!
    private let allowedOrigins = ["https://yourdomain.com", "https://www.yourdomain.com"]
    private let messageHandlerName = "nativeHandler"
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupWebView()
        loadWebsite()
    }
    
    private func setupWebView() {
        let configuration = WKWebViewConfiguration()
        configuration.preferences.javaScriptEnabled = true
        configuration.preferences.javaScriptCanOpenWindowsAutomatically = false
        
        let contentController = WKUserContentController()
        contentController.add(self, name: messageHandlerName)
        configuration.userContentController = contentController
        
        webView = WKWebView(frame: .zero, configuration: configuration)
        webView.navigationDelegate = self
        webView.uiDelegate = self
        webView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(webView)
        
        NSLayoutConstraint.activate([
            webView.topAnchor.constraint(equalTo: view.topAnchor),
            webView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            webView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            webView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
    }
    
    private func loadWebsite() {
        guard let url = URL(string: "https://yourdomain.com") else { return }
        let request = URLRequest(url: url)
        webView.load(request)
    }
    
    private func isOriginAllowed(_ url: URL?) -> Bool {
        guard let url = url,
              let scheme = url.scheme,
              let host = url.host else {
            return false
        }
        
        let origin = "\(scheme)://\(host)"
        return allowedOrigins.contains(origin)
    }
    
    private func validateMessage(_ message: [String: Any]) -> Bool {
        guard let action = message["action"] as? String,
              !action.isEmpty else {
            return false
        }
        
        let allowedActions = ["requestCamera", "requestNotifications", "requestPurchase"]
        return allowedActions.contains(action)
    }
    
    private func sendResponse(success: Bool, data: [String: Any]? = nil, error: String? = nil) {
        var response: [String: Any] = ["success": success]
        if let data = data {
            response["data"] = data
        }
        if let error = error {
            response["error"] = error
        }
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: response),
              let jsonString = String(data: jsonData, encoding: .utf8) else {
            return
        }
        
        let script = "window.nativeResponse(\(jsonString));"
        webView.evaluateJavaScript(script, completionHandler: nil)
    }
}

extension SecureWebViewController: WKScriptMessageHandler {
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard message.name == messageHandlerName,
              isOriginAllowed(webView.url),
              let messageBody = message.body as? [String: Any],
              validateMessage(messageBody) else {
            sendResponse(success: false, error: "Invalid message or origin")
            return
        }
        
        guard let action = messageBody["action"] as? String else {
            sendResponse(success: false, error: "Missing action")
            return
        }
        
        switch action {
        case "requestCamera":
            handleCameraRequest(parameters: messageBody["parameters"] as? [String: Any])
        case "requestNotifications":
            handleNotificationRequest()
        case "requestPurchase":
            handlePurchaseRequest(parameters: messageBody["parameters"] as? [String: Any])
        default:
            sendResponse(success: false, error: "Unknown action")
        }
    }
    
    private func handleCameraRequest(parameters: [String: Any]?) {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        
        switch status {
        case .authorized:
            presentCamera()
        case .notDetermined:
            AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                DispatchQueue.main.async {
                    if granted {
                        self?.presentCamera()
                    } else {
                        self?.sendResponse(success: false, error: "Camera access denied")
                    }
                }
            }
        case .denied, .restricted:
            sendResponse(success: false, error: "Camera access denied or restricted")
        @unknown default:
            sendResponse(success: false, error: "Unknown camera authorization status")
        }
    }
    
    private func presentCamera() {
        guard UIImagePickerController.isSourceTypeAvailable(.camera) else {
            sendResponse(success: false, error: "Camera not available")
            return
        }
        
        let picker = UIImagePickerController()
        picker.sourceType = .camera
        picker.delegate = self
        picker.allowsEditing = false
        present(picker, animated: true)
    }
    
    private func handleNotificationRequest() {
        UNUserNotificationCenter.current().getNotificationSettings { [weak self] settings in
            DispatchQueue.main.async {
                switch settings.authorizationStatus {
                case .authorized, .provisional:
                    self?.registerForNotifications()
                case .notDetermined:
                    self?.requestNotificationPermission()
                case .denied:
                    self?.sendResponse(success: false, error: "Notification permission denied")
                case .ephemeral:
                    self?.sendResponse(success: false, error: "Ephemeral notification status")
                @unknown default:
                    self?.sendResponse(success: false, error: "Unknown notification status")
                }
            }
        }
    }
    
    private func requestNotificationPermission() {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .sound, .badge]) { [weak self] granted, error in
            DispatchQueue.main.async {
                if granted {
                    self?.registerForNotifications()
                } else {
                    self?.sendResponse(success: false, error: error?.localizedDescription ?? "Permission denied")
                }
            }
        }
    }
    
    private func registerForNotifications() {
        UIApplication.shared.registerForRemoteNotifications()
        sendResponse(success: true, data: ["status": "registered"])
    }
    
    private func handlePurchaseRequest(parameters: [String: Any]?) {
        guard let productId = parameters?["productId"] as? String,
              !productId.isEmpty else {
            sendResponse(success: false, error: "Invalid product ID")
            return
        }
        
        guard SKPaymentQueue.canMakePayments() else {
            sendResponse(success: false, error: "Payments not allowed")
            return
        }
        
        let productIds: Set<String> = [productId]
        let request = SKProductsRequest(productIdentifiers: productIds)
        request.delegate = self
        request.start()
    }
}

extension SecureWebViewController: WKNavigationDelegate {
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        if isOriginAllowed(url) {
            decisionHandler(.allow)
        } else {
            if UIApplication.shared.canOpenURL(url) {
                UIApplication.shared.open(url, options: [:], completionHandler: nil)
            }
            decisionHandler(.cancel)
        }
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        injectBridgeScript()
    }
    
    private func injectBridgeScript() {
        let script = """
        window.nativeBridge = {
            call: function(action, parameters) {
                if (window.webkit && window.webkit.messageHandlers && window.webkit.messageHandlers.\(messageHandlerName)) {
                    window.webkit.messageHandlers.\(messageHandlerName).postMessage({
                        action: action,
                        parameters: parameters || {}
                    });
                }
            },
            requestCamera: function() {
                this.call('requestCamera');
            },
            requestNotifications: function() {
                this.call('requestNotifications');
            },
            requestPurchase: function(productId) {
                this.call('requestPurchase', { productId: productId });
            }
        };
        
        window.nativeResponse = function(response) {
            var event = new CustomEvent('nativeResponse', { detail: response });
            window.dispatchEvent(event);
        };
        """
        
        webView.evaluateJavaScript(script, completionHandler: nil)
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        showError(message: "Navigation failed: \(error.localizedDescription)")
    }
    
    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        showError(message: "Failed to load: \(error.localizedDescription)")
    }
    
    private func showError(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

